import { GoogleGenAI } from "@google/genai";

/**
 * Uses Gemini to explain the C code logic to the user.
 */
export const explainCodeLogic = async (code: string): Promise<string> => {
  // NOTE: process.env.API_KEY is expected to be available in the build environment.
  // In a real production app, this would likely be proxied through a backend.
  if (!process.env.API_KEY) {
      throw new Error("API Key not found");
  }

  // Initializing GoogleGenAI with apiKey from process.env.API_KEY
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    // Using gemini-3-flash-preview for text analysis task
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a senior C developer. Explain the following C code for BiDi (Bidirectional) text correction to a junior developer.

      Please provide the explanation in Hebrew.

      Focus on:
      1. Why we check for 0xD6/0xD7 for Hebrew.
      2. Why RLM (0xE2 0x80 0x8F) is added after punctuation in English context.
      3. Memory allocation strategy.

      Keep the explanation concise, bulleted, and technically accurate.

      Code:
      ${code}`,
    });

    // response.text is a property, not a method
    return response.text || "No explanation generated.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

/**
 * Uses Gemini to analyze raw text and explain why it displays incorrectly (BiDi issues).
 */
export const analyzeTextIssues = async (text: string): Promise<string> => {
  if (!process.env.API_KEY) {
      throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `You are a Unicode and Bidirectional Text (BiDi) Expert.
      Analyze the following Hebrew/English text snippet provided by a user.
      The user complains that the text looks broken, fragmented, or has weird punctuation spacing after copying it from an AI Chatbot (like ChatGPT) or a website.

      Your goal: Explain in Hebrew *why* this specific text causes display issues.

      Look for:
      1. Invisible Unicode Control Characters (RLE U+202B, PDF U+202C, LRM, RLM).
      2. "Logical" vs "Visual" ordering issues.
      3. Native punctuation vs ASCII punctuation.

      Input Text:
      """
      ${text.substring(0, 1000)}
      """

      Provide a concise, technical but accessible explanation in Hebrew. Explain that ChatGPT often wraps text in embedding codes that cause these "islands" of directionality when pasted elsewhere.
      `,
    });

    return response.text || "לא ניתן היה לייצר ניתוח לטקסט זה.";
  } catch (error) {
    console.error("Gemini Analysis Error:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { 
  Check, Eraser, Eye, EyeOff, ClipboardCopy, Wand2, BarChart3, Languages, Globe2, 
  Zap, ArrowRightLeft, Hash, Sparkles, BookOpen, Cpu, Smile, FileText, HelpCircle, Microscope, Bot
} from 'lucide-react';
import { statsService } from '../services/statsService';
import { analyzeTextIssues } from '../services/geminiService';

// Unicode Control Characters
const RLM = '\u200F';
const RLE = '\u202B';
const PDF = '\u202C';

// Hebrew Native Punctuation
const HEB_MAQAF = '\u05BE';      // ־
const HEB_GERESH = '\u05F3';     // ׳
const HEB_GERSHAYIM = '\u05F4';  // ״

// Expanded set of weak punctuation marks that need RLM anchoring in mixed text
const WEAK_PUNCTUATION = new Set([
  ':', ';', '.', ',', '?', '!', 
  '-', '–', '—', // Hyphens, En-dash, Em-dash (Critical for "high-quality" and separator clauses)
  '_',           // Underscores (Critical for signature lines)
  '/', '\\', '|', // Slashes and pipes
  '@', '#', '*', // Symbols often used in social/business context
  '+', '=', '~'  // Math symbols
]);

const BRACKETS = new Set(['(', ')', '[', ']', '{', '}', '<', '>']);

const LANGUAGE_FACTS = [
  // Technical / Unicode
  { title: "Emoji Logic", content: "אימוג'ים הם לרוב תווים 'ניטרליים' ביוניקוד. ללא תיקון, הם עלולים לקפוץ לצד הלא נכון של השורה כשהם ממוקמים בסוף משפט בעברית." },
  { title: "Surrogate Pairs", content: "רוב האימוג'ים תופסים 4 בייטים ב-UTF-16. אם עוברים על המחרוזת לפי אינדקס פשוט, עלולים 'לחתוך' אימוג'י לשניים ולגרום לשגיאות תצוגה." },
  { title: "RLM & Emojis", content: "הצמדת RLM לאימוג'י מבטיחה שהוא ייחשב כחלק מההקשר העברי ולא 'ייגרר' אחרי מילה באנגלית שבאה לפניו." },
  { title: "Visual vs Logical", content: "בשנות ה-90 (עידן HTML 3.2), אתרים בעברית נכתבו הפוך (Visual Hebrew) כדי שהדפדפן יציג אותם ישר. הקוד היה נראה כמו 'olleh' במקום 'hello'." },
  { title: "האלגוריתם של יוניקוד (UBA)", content: "תקן ה-BiDi Algorithm של יוניקוד משתרע על פני עשרות עמודי חוקים רק כדי לקבוע איך סימני פיסוק ניטרליים יתנהגו בין שפות שונות." },
  { title: "Zero Width Joiner", content: "התו ZWJ משמש ביוניקוד כדי 'להדביק' אימוג'ים מורכבים. למשל, אימוג'י של משפחה הוא בעצם רצף של: איש + ZWJ + אישה + ZWJ + ילד." },

  // Hebrew Language
  { title: "Abjad", content: "עברית מוגדרת כ-'Abjad' – מערכת כתב שבה האותיות מייצגות בעיקר עיצורים. הניקוד (Vowels) הומצא מאוחר יותר בטבריה כדי לשמר את ההגייה הנכונה." },
  { title: "אותיות מנצפ״ך", content: "האותיות הסופיות נוצרו מסיבה גרפית היסטורית: כשכתבו על מגילות קלף, היה קל ומהיר יותר למשוך את הקו כלפי מטה בסוף מילה במקום לעצור ולסגור את האות." },
  { title: "שפת הקודש למחשב", content: "לפני תקן Unicode, נעשה שימוש ב-ISO-8859-8. בגלל חוסר מקום, התקן כלל רק אותיות ולא ניקוד, מה שעיכב את השימוש הממוחשב בניקוד בשנים רבות." },

  // Office & Productivity
  { title: "באג ה-Word המפורסם", content: "בגרסאות ישנות של Word, שילוב של סוגריים ומספרים בתוך טקסט עברי גרם לעיתים קרובות להיפוך הסוגר השני. זו הסיבה שרבים התרגלו לכתוב סוגריים הפוכים בכוונה." },
  { title: "הפונט דוד (David)", content: "הגופן הנפוץ 'דוד' עוצב ב-1954 ע״י איתמר דוד. אין לו באמת גרסת Bold (מודגש) מקורית; המחשב פשוט מעבה את הקווים מתמטית, מה שלעיתים מעוות את האותיות." },
  { title: "Alt+Shift", content: "הקיצור המפורסם להחלפת שפה הוא שריד היסטורי ממערכות הפעלה שבהן החלפת שפה דרשה טעינה מחדש של מפת מקשים (Keyboard Map) לזיכרון הראם." },
  { title: "Caps Lock בעברית", content: "במקלדות עבריות, מקש ה-Caps Lock משמש לעיתים להקלדת ניקוד (בתוספת Shift) או לשינוי זמני לאנגלית, תלוי בהגדרות מערכת ההפעלה, כיוון שאין אותיות גדולות בעברית." },
  { title: "אריאל (Arial)", content: "הפונט אריאל בעברית הוא למעשה חיקוי של גופן 'הלווטיקה'. מיקרוסופט כללה אותו ב-Windows 3.1 כדי לחסוך בתשלומי רישוי, והוא הפך לסטנדרט דה-פקטו." }
];

// High-Fidelity Word Export Wrapper
const getWordFriendlyHtml = (content: string) => {
    return `
    <html xmlns:o='urn:schemas-microsoft-com:office:office' xmlns:w='urn:schemas-microsoft-com:office:word' xmlns='http://www.w3.org/TR/REC-html40'>
    <head>
        <meta charset="utf-8">
        <title>Document</title>
        <style>
            /* Default RTL Body Style */
            body { 
                font-family: 'David', 'Arial', sans-serif; 
                font-size: 12pt; 
                direction: rtl; 
                text-align: right;
            }

            /* High-Quality List Handling for Word */
            ul, ol {
                margin-top: 0;
                margin-bottom: 0;
                direction: rtl;
                unicode-bidi: embed;
            }

            /* Ensure bullets/numbers stay on the right side */
            li {
                direction: rtl;
                text-align: right;
                margin-right: 24pt; /* Indent for bullet */
