interface FixStats {
    totalChars: number;
    replaced: number;
    anchored: number;
    interventionRate: number;
}

export const BidiFixer: React.FC = () => {
  const [outputText, setOutputText] = useState<string>('');
  const [outputRichHtml, setOutputRichHtml] = useState<string>('');
  const [stats, setStats] = useState<FixStats | null>(null);
  const [activeFact, setActiveFact] = useState<typeof LANGUAGE_FACTS[0] | null>(null);
  const [copied, setCopied] = useState<'rich' | 'plain' | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);
  const [showRawInput, setShowRawInput] = useState(false);
  const [viewMode, setViewMode] = useState<'raw' | 'formatted'>('formatted');

  const inputRef = useRef<HTMLDivElement>(null);
  const outputFormattedRef = useRef<HTMLDivElement>(null);

  const isEmoji = (char: string) => {
    const emojiRegex = /\p{Emoji_Presentation}|\p{Emoji}\uFE0F|\p{Emoji_Modifier_Base}/u;
    return emojiRegex.test(char);
  };

  const isHebrew = (char: string | undefined) => {
    if (!char) return false;
    const code = char.charCodeAt(0);
    return code >= 0x0590 && code <= 0x05FF;
  };

  const isEnglishOrDigit = (char: string | undefined) => {
    if (!char) return false;
    return /[a-zA-Z0-9]/.test(char);
  }

  // Lookahead to find the next "Strong" character (skipping spaces/neutrals)
  const getNextStrongDir = (currentIndex: number, allChars: string[]): 'hebrew' | 'english' | 'none' => {
      for (let i = currentIndex + 1; i < allChars.length; i++) {
          const c = allChars[i];
          if (isHebrew(c)) return 'hebrew';
          if (isEnglishOrDigit(c)) return 'english';
          // If we hit a new line, stop
          if (c === '\n' || c === '\r') return 'none';
      }
      return 'none';
  };

  // Lookbehind to find the previous "Strong" character
  const getPrevStrongDir = (currentIndex: number, allChars: string[]): 'hebrew' | 'english' | 'none' => {
      for (let i = currentIndex - 1; i >= 0; i--) {
          const c = allChars[i];
          if (isHebrew(c)) return 'hebrew';
          if (isEnglishOrDigit(c)) return 'english';
          if (c === '\n' || c === '\r') return 'none';
      }
      return 'none';
  };

  const ultimateBidiAlgorithm = (text: string) => {
      let resultText = RLE;
      let replacedCount = 0;
      let anchoredCount = 0;

      const normalized = text.split('\u00A0').join(' ');
      const chars = Array.from(normalized);

      for (let i = 0; i < chars.length; i++) {
        let char = chars[i];
        const prev = chars[i - 1];
        const next = chars[i + 1];

        // 1. Handle Em-dash
        if (char === '—') {
            char = '-';
            replacedCount++;
        }

        // 2. Smart Bracket Handling
        if (OPEN_BRACKETS.has(char)) {
            const nextStrong = getNextStrongDir(i, chars);

            if (nextStrong === 'english') {
                // CASE: Bracket starts English phrase inside Hebrew text. 
                // e.g., "Hebrew (English..."
                // Logic: 
                // 1. RLM to close previous Hebrew context.
                // 2. LRM to start explicit LTR context for the bracket + content.
                resultText += RLM + LRM + char;
                anchoredCount += 2;
            } else {
                // CASE: Standard Hebrew bracket
                // e.g., "Hebrew (Hebrew..."
                resultText += RLM + char;
                anchoredCount++;
            }
            continue;
        }

        if (CLOSE_BRACKETS.has(char)) {
            const prevStrong = getPrevStrongDir(i, chars);
            const nextStrong = getNextStrongDir(i, chars);

            if (prevStrong === 'english') {
                // CASE: Closing an English phrase.
                // e.g., "...English)"

                // Sub-decision: What comes next?
                if (nextStrong === 'english') {
                    // "...English) and (More..."
                    // Keep LTR context alive
                    resultText += char + LRM;
                    anchoredCount++;
                } else {
                    // "...English). Hebrew" OR "...English), Hebrew"
                    // Close LTR context, Switch back to RTL (RLM) for the punctuation/Hebrew
                    resultText += char + LRM + RLM;
                    anchoredCount += 2;
                }
            } else {
                // CASE: Closing a Hebrew phrase
                resultText += char + RLM;
                anchoredCount++;
            }
            continue;
        }

        // 3. Handle Smart Quotes
        if (char === '"') {
            resultText += HEB_GERSHAYIM;
            replacedCount++;
            continue;
        } else if (char === "'") {
            resultText += HEB_GERESH;
            replacedCount++;
            continue;
        } 

        // 4. Critical Logic: Hyphens in Hebrew Compounds
        if ((char === '-' || char === HEB_MAQAF) && isHebrew(prev) && isHebrew(next)) {
             resultText += char;
             continue;
        }

        resultText += char;

        // 5. Intelligent Punctuation Anchoring
        if (isEmoji(char)) {
            resultText += RLM;
            anchoredCount++;
            continue;
        }

        if (WEAK_PUNCTUATION.has(char)) {
            // Check context using lookahead
            const nextStrong = getNextStrongDir(i, chars);

            // CASE A: English/Digit ahead (e.g., "100: Secrets" or "Version 1.0")
            // DO NOT add RLM. Let the LTR run continue naturally.
            if (nextStrong === 'english') {
                continue;
            }

            // CASE B: Hebrew ahead (e.g., "word, Hebrew")
            // DO NOT add RLM. The following Hebrew letter naturally pulls the punctuation to the right place.
            if (nextStrong === 'hebrew') {
                continue; 
            }

            // CASE C: End of text or End of Line
            // Add RLM to ensure the punctuation marks the end of the RTL sentence correctly.
            resultText += RLM;
            anchoredCount++;
        }
      }

      resultText += PDF;
      return { fixedText: resultText, replaced: replacedCount, anchored: anchoredCount };
  };

  const processContent = (html: string) => {
    const container = document.createElement('div');
    container.innerHTML = html;

    const walker = document.createTreeWalker(container, NodeFilter.SHOW_TEXT, null);
    let currentNode: Node | null = walker.nextNode();
    let totalReplaced = 0;
    let totalAnchored = 0;
    let totalChars = 0;
    let fullPlainText = '';

    while (currentNode) {
      const originalText = currentNode.nodeValue || '';
      if (originalText.trim().length > 0) {
          totalChars += Array.from(originalText).length;
          const result = ultimateBidiAlgorithm(originalText);
          totalReplaced += result.replaced;
          totalAnchored += result.anchored;
          currentNode.nodeValue = result.fixedText;
          fullPlainText += result.fixedText;
      }
      currentNode = walker.nextNode();
    }

    const interventionRate = totalChars > 0 ? ((totalReplaced + totalAnchored) / totalChars) * 100 : 0;

    return { 
        html: container.innerHTML, 
        text: fullPlainText, 
        stats: { totalChars, replaced: totalReplaced, anchored: totalAnchored, interventionRate } 
    };
  };

  const handleFix = () => {
    setIsProcessing(true);
    const randomFact = LANGUAGE_FACTS[Math.floor(Math.random() * LANGUAGE_FACTS.length)];

    setTimeout(() => {
        const currentHtml = inputRef.current?.innerHTML || '';
