export interface GlobalStatsData {
  totalCharsAllTime: number;
  totalCharsMonth: number;
  totalCharsWeek: number;
  totalReplacements: number;
  usageCount: number;
  lastUpdated: string;
  weekId: string;
  monthId: string;
}

const API_BASE_URL = '/api/stats'; // Assumes the API is served from the same domain on Azure
const EVENT_KEY = 'kivun_stats_updated';

const getInitialStats = (): GlobalStatsData => {
  const now = new Date();
  return {
    totalCharsAllTime: 0,
    totalCharsMonth: 0,
    totalCharsWeek: 0,
    totalReplacements: 0,
    usageCount: 0,
    lastUpdated: now.toISOString(),
    weekId: '',
    monthId: '',
  };
};

export const statsService = {
  // Fetch stats from Azure Server
  getStats: async (): Promise<GlobalStatsData> => {
    try {
      const response = await fetch(API_BASE_URL);
      if (!response.ok) throw new Error('Network response was not ok');
      return await response.json();
    } catch (e) {
      console.warn("Failed to fetch global stats, showing empty/local state", e);
      return getInitialStats();
    }
  },

  // Send update to Azure Server
  updateStats: async (charsCount: number, replacementsCount: number) => {
    try {
        await fetch(API_BASE_URL, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chars: charsCount, replacements: replacementsCount })
        });

        // Notify UI components to re-fetch
        window.dispatchEvent(new Event(EVENT_KEY));
    } catch (e) {
        console.error("Failed to update global stats", e);
    }
  },

  // Send reset command to Azure Server
  resetStats: async (password: string): Promise<boolean> => {
    try {
        const response = await fetch(`${API_BASE_URL}/reset`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ password })
        });

        if (response.ok) {
            window.dispatchEvent(new Event(EVENT_KEY));
            return true;
        }
        return false;
    } catch (e) {
        console.error("Failed to reset stats", e);
        return false;
    }
  },

  subscribe: (callback: () => void) => {
    window.addEventListener(EVENT_KEY, callback);
    return () => window.removeEventListener(EVENT_KEY, callback);
  }
};

