import express from 'express';
import path from 'path';
import fs from 'fs';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 8080;
const DB_FILE = path.join(__dirname, 'stats.json');

app.use(express.json());
// Serve static files from the build folder (dist)
app.use(express.static(path.join(__dirname, 'dist')));

// --- Database Helper Functions (Simple JSON File) ---

const getInitialStats = () => ({
    totalCharsAllTime: 0,
    totalCharsMonth: 0,
    totalCharsWeek: 0,
    totalReplacements: 0,
    usageCount: 0,
    lastUpdated: new Date().toISOString(),
    weekId: getWeekId(),
    monthId: getMonthId()
});

const getWeekId = () => {
    const d = new Date();
    const onejan = new Date(d.getFullYear(), 0, 1);
    const week = Math.ceil((((d.getTime() - onejan.getTime()) / 86400000) + onejan.getDay() + 1) / 7);
    return `${d.getFullYear()}-W${week}`;
};

const getMonthId = () => {
    const d = new Date();
    return `${d.getFullYear()}-${d.getMonth() + 1}`;
};

const readDb = () => {
    try {
        if (fs.existsSync(DB_FILE)) {
            const data = JSON.parse(fs.readFileSync(DB_FILE, 'utf8'));
            return { ...getInitialStats(), ...data }; // Merge to ensure all fields exist
        }
    } catch (e) {
        console.error("Error reading DB:", e);
    }
    return getInitialStats();
};

const writeDb = (data) => {
    try {
        fs.writeFileSync(DB_FILE, JSON.stringify(data, null, 2));
    } catch (e) {
        console.error("Error writing DB:", e);
    }
};

// --- API Routes ---

// GET Stats
app.get('/api/stats', (req, res) => {
    res.json(readDb());
});

// UPDATE Stats
app.post('/api/stats', (req, res) => {
    const { chars, replacements } = req.body;

    const data = readDb();
    const currentWeek = getWeekId();
    const currentMonth = getMonthId();

    // Reset counters if period changed
    if (data.weekId !== currentWeek) {
        data.totalCharsWeek = 0;
        data.weekId = currentWeek;
    }
    if (data.monthId !== currentMonth) {
        data.totalCharsMonth = 0;
        data.monthId = currentMonth;
    }

    // Update values
    const c = parseInt(chars) || 0;
    const r = parseInt(replacements) || 0;

    data.totalCharsAllTime += c;
    data.totalCharsMonth += c;
    data.totalCharsWeek += c;
    data.totalReplacements += r;
    data.usageCount += 1;
    data.lastUpdated = new Date().toISOString();

    writeDb(data);
    res.json({ success: true, data });
});

// RESET Stats
app.post('/api/stats/reset', (req, res) => {
    const { password } = req.body;

    // Simple authentication
    if (password === 'admin' || password === process.env.ADMIN_PASSWORD) { 
        const freshStats = getInitialStats();
        writeDb(freshStats);
        return res.json({ success: true, data: freshStats });
    }

    res.status(403).json({ error: 'Invalid password' });
});

// --- Serve React App (Catch-All) ---
// Any request that doesn't match an API route is sent to index.html
app.get('*', (req, res) => {
    res.sendFile(path.join(__dirname, 'dist', 'index.html'));
});

app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
    console.log(`API available at http://localhost:${PORT}/api/stats`);
});

