            <p className="text-xs font-medium text-slate-500 dark:text-slate-400">
                תוכנה זו נוצרה ע״י <span className="font-bold text-slate-700 dark:text-slate-200">Amit Hacoon</span>
            </p>
        </div>

      </div>
    </div>
  );
};

